/**
 * CAP Theorem Examples in Real Systems
 * =====================================
 *
 * CP Systems (Consistency + Partition Tolerance):
 * - HBase, Zookeeper, etcd, Consul
 * - MySQL with synchronous replication
 * - Behavior: On partition, some nodes refuse requests
 *
 * AP Systems (Availability + Partition Tolerance):
 * - Cassandra, DynamoDB, CouchDB
 * - DNS, CDNs
 * - Behavior: On partition, serve possibly stale data
 *
 * Real examples:
 *
 * 1. Bank account balance → CP (money must be consistent)
 *    During partition: decline transaction rather than risk double-spend
 *
 * 2. Social media 'likes' count → AP (slight inconsistency OK)
 *    During partition: show cached count, sync later
 *
 * 3. Distributed lock (etcd/Zookeeper) → CP
 *    Can't have two nodes believe they have the lock simultaneously
 *
 * 4. Shopping cart → AP (Amazon's Dynamo paper)
 *    Show cart contents from local replica, merge conflicts on checkout
 */

// ── Java: Simulating AP eventual consistency ──────────────────────
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class EventualConsistency {

    // Two 'nodes' with independent counters (like view count)
    static AtomicLong nodeA = new AtomicLong(100);
    static AtomicLong nodeB = new AtomicLong(100);
    static boolean partitioned = false;

    static void increment(String node) {
        if (node.equals("A")) nodeA.incrementAndGet();
        else nodeB.incrementAndGet();
    }

    // Sync: converge to max (last-write-wins for counters = max)
    static void sync() {
        if (!partitioned) {
            long max = Math.max(nodeA.get(), nodeB.get());
            nodeA.set(max);
            nodeB.set(max);
        }
    }

    public static void main(String[] args) throws Exception {
        // Simulate partition: both nodes diverge
        partitioned = true;
        increment("A"); increment("A"); increment("B"); // independent
        System.out.println("During partition: A=" + nodeA.get() + ", B=" + nodeB.get()); // A=102, B=101

        // Heal partition: sync
        partitioned = false;
        sync();
        System.out.println("After sync: A=" + nodeA.get() + ", B=" + nodeB.get()); // A=102, B=102
        // Eventual consistency: both converge to 102 (highest seen)
    }
}

import java.util.*;

/**
 * Consistent Hashing
 * Problem with simple hash(key) % N sharding:
 * - Adding/removing 1 node reshards ~(N-1)/N of all keys
 * - Consistent hashing: adding 1 node reshards only ~1/N keys
 */
public class ConsistentHashing {

    static final int RING_SIZE = 360; // positions on the ring
    static final int VIRTUAL_NODES = 3; // virtual nodes per physical server

    static TreeMap<Integer, String> ring = new TreeMap<>();

    static void addNode(String node) {
        for (int v = 0; v < VIRTUAL_NODES; v++) {
            int pos = hash(node + "-vnode-" + v);
            ring.put(pos, node);
        }
    }

    static void removeNode(String node) {
        ring.entrySet().removeIf(e -> e.getValue().equals(node));
    }

    static String getNode(String key) {
        if (ring.isEmpty()) throw new RuntimeException("No nodes in ring");
        int pos = hash(key);
        // Find first node clockwise from key's position
        Map.Entry<Integer, String> entry = ring.ceilingEntry(pos);
        return (entry != null ? entry : ring.firstEntry()).getValue();
    }

    static int hash(String key) {
        return Math.abs(key.hashCode() % RING_SIZE);
    }

    public static void main(String[] args) {
        addNode("server-1");
        addNode("server-2");
        addNode("server-3");

        System.out.println("Ring size: " + ring.size()); // 9 (3 servers * 3 vnodes)

        // Show key → server mapping
        String[] keys = {"user:1", "user:2", "user:3", "topic:42", "session:abc"};
        for (String key : keys)
            System.out.println(key + " → " + getNode(key));

        // Add new node: only keys between old predecessor and new node move
        System.out.println("\nAdding server-4:");
        addNode("server-4");
        for (String key : keys)
            System.out.println(key + " → " + getNode(key)); // some may change

        // Remove a node: its keys go to successor
        System.out.println("\nRemoving server-2:");
        removeNode("server-2");
        for (String key : keys)
            System.out.println(key + " → " + getNode(key));
    }
}

