public class Q1 {
    public static void main(String[] args) {
        int N_old = 3, N_new = 4;
        int changed = 0, total = 12; // check keys 0-11

        for (int key = 0; key < total; key++) {
            int oldShard = key % N_old;
            int newShard = key % N_new;
            if (oldShard != newShard) changed++;
            System.out.println("key=" + key + ": old=shard" + oldShard + " new=shard" + newShard
                + (oldShard != newShard ? " MOVED" : ""));
        }
        System.out.println("Moved: " + changed + "/" + total + " = " + (100*changed/total) + "%");
        System.out.println("Consistent hashing: only ~" + (100/N_new) + "% would move");
    }
}

